}

Method.Source:
/// <summary>
/// Extension of the <c>mustGoBatch</c> method to enable debugging during development.
/// </summary>
/// <remarks>
/// This is done because batch processes cannot be executed in development due to GIT.
/// </remarks>
/// <returns>
/// Returns a boolean value.
/// </returns>
public boolean mustGoBatch()
{
    next mustGoBatch();

    return false;
}
